      const fltSemantics &SrcSem =
          X->getType()->getScalarType()->getFltSemantics();
      bool Lossy;
      APFloat WideC = *C;
      WideC.convert(SrcSem, APFloat::rmNearestTiesToEven, &Lossy);
      assert(!Lossy && "Conversion from float to wider type should be exact");

      // For ordered comparisons, we can compute an adjusted constant:
      //   fptrunc(X) >= C  -->  X >= lower_bound(C)
      //   fptrunc(X) >  C  -->  X >  upper_bound(C)
      //   fptrunc(X) <= C  -->  X <= upper_bound(C)
      //   fptrunc(X) <  C  -->  X <  lower_bound(C)
      // where lower_bound(C) is the midpoint between C and the next smaller
      // float, and upper_bound(C) is the midpoint between C and the next
      // larger float.
      //
      // This also works for unordered comparisons (UGT, UGE, ULT, ULE)
      // since the ordered/unordered distinction only affects NaN handling,
      // which is preserved.

      if (C->isNaN() || C->isInfinity() || !C->isNormal())
        return nullptr;

      bool NeedLowerBound, NeedUpperBound;
      switch (Pred) {
      default:
        return nullptr;
      case FCmpInst::FCMP_OGT:
      case FCmpInst::FCMP_UGT:
      case FCmpInst::FCMP_OLE:
      case FCmpInst::FCMP_ULE:
        NeedLowerBound = false;
        NeedUpperBound = true;
        break;
      case FCmpInst::FCMP_OGE:
      case FCmpInst::FCMP_UGE:
      case FCmpInst::FCMP_OLT:
      case FCmpInst::FCMP_ULT:
        NeedLowerBound = true;
        NeedUpperBound = false;
        break;
      }

      // Compute the midpoint between C and its neighbor in float semantics.
      // This midpoint is exactly representable in the wider type.
      APFloat NeighborC(*C);
      NeighborC.next(NeedLowerBound /*nextDown*/);
      APFloat NeighborWide = NeighborC;
      bool Lossy2;
      NeighborWide.convert(SrcSem, APFloat::rmNearestTiesToEven, &Lossy2);
      assert(!Lossy2 &&
             "Conversion from float to wider type should be exact");

      // Midpoint = (WideC + NeighborWide) / 2
      APFloat NewC = WideC;
      NewC.add(NeighborWide, APFloat::rmNearestTiesToEven);
      NewC.divide(APFloat(SrcSem, "2"), APFloat::rmNearestTiesToEven);

      Constant *NewConst = ConstantFP::get(X->getType(), NewC);
      return new FCmpInst(Pred, X, NewConst, "", &I);
    }
  }

